package multiversx

import "testing"

const (
	mvxMnemonic = "abandon abandon abandon abandon abandon abandon abandon abandon abandon abandon abandon about"
	mvxPath     = "m/44'/508'/0'/0'/0'"
	mvxAddr     = "erd1sqhjrtmsn5yjk6w85099p8v0ly0g8z9pxeqe5dvu5rlf2n7vq3vqytny9g"
	mvxNative   = "0xeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee"
	mvxToken    = "USDC-c76f1f"
)

type mvxVector struct {
	name      string
	contract  string
	amount    string
	gasLimit  string
	unsigned  string
	signature string
	signed    string
	txHash    string
}

func mvxVectors() []mvxVector {
	return []mvxVector{
		{
			name:      "native_transfer",
			contract:  mvxNative,
			amount:    "1000000000000000000",
			gasLimit:  "50000",
			unsigned:  "",
			signature: "cf62870d85d13c918618780a43389165eb5a4ed7760af9d17d7f3cbad73fdb816881afdbbfeb47aefc416295b86f71d02226015cc6063b10a844df4b3d63b407",
			signed:    "",
			txHash:    "8138dd2d359e483d4495d651f553408ae4866ef8dece3fc345c73756d9814301",
		},
		{
			name:      "esdt_transfer",
			contract:  mvxToken,
			amount:    "12345",
			gasLimit:  "500000",
			unsigned:  "",
			signature: "2c8143387442835a7c43fb6d9e53dc049d247140c0bfaa8a40dcd2dcbf69cd44f1bcef1348e0bf2cc2e6e2544e22fb49cc952212a508817902406dcb7e86cc0b",
			signed:    "",
			txHash:    "12d7be7ecb89cd062d6c3e3de5ffdfe2fc91e34be6b0c0802a5ee585ea4c5ee9",
		},
	}
}

func TestMultiversxVectors(t *testing.T) {
	acc, err := NewAccountFromMnemonic(mvxMnemonic, mvxPath)
	if err != nil {
		t.Fatal(err)
	}
	if acc.Address() != mvxAddr {
		t.Fatalf("address mismatch: got %s want %s", acc.Address(), mvxAddr)
	}

	for _, v := range mvxVectors() {
		t.Run(v.name, func(t *testing.T) {
			b := NewTxBuilder(&Ingredient{
				TxType:          "0",
				ContractAddress: v.contract,
				Sender:          mvxAddr,
				Recipient:       mvxAddr,
				Amount:          v.amount,
				Nonce:           "5",
				NetWorkConfig: &NetWorkConfig{
					GasPrice: "1000000000",
					GasLimit: v.gasLimit,
					ChainID:  "1",
					Version:  "1",
				},
			})
			if err := b.Build(); err != nil {
				t.Fatalf("build: %v", err)
			}
			if b.GetUnsignedHex() != v.unsigned {
				t.Fatalf("unsigned mismatch:\n got %s\nwant %s", b.GetUnsignedHex(), v.unsigned)
			}
			sig, err := b.Sign(acc.PrivateKey())
			if err != nil {
				t.Fatalf("sign: %v", err)
			}
			if sig != v.signature {
				t.Fatalf("signature mismatch:\n got %s\nwant %s", sig, v.signature)
			}
			signed, err := b.ConcatSignature(sig, false)
			if err != nil {
				t.Fatalf("concat: %v", err)
			}
			if signed != v.signed {
				t.Fatalf("signed mismatch:\n got %s\nwant %s", signed, v.signed)
			}
			if b.GetTxHash() != v.txHash {
				t.Fatalf("txHash mismatch: got %s want %s", b.GetTxHash(), v.txHash)
			}
		})
	}
}
